import java.util.*;

class Solution {

    // Function to find the next greater element for each element in the circular array
    public int[] nextGreaterElements(int[] arr) {
        int n = arr.length;

        // To store the next greater elements
        int[] ans = new int[n];
        Arrays.fill(ans, -1);

        // Traverse each element to find its next greater
        for (int i = 0; i < n; i++) {
            int currEle = arr[i];

            // Look ahead in circular manner
            for (int j = 1; j < n; j++) {
                int ind = (i + j) % n;

                if (arr[ind] > currEle) {
                    ans[i] = arr[ind];
                    break;
                }
            }
        }

        return ans;
    }
}

public class Main {
    public static void main(String[] args) {
        int[] arr = {5, 7, 1, 7, 6, 0};

        // Creating instance of Solution
        Solution sol = new Solution();

        // Call function
        int[] ans = sol.nextGreaterElements(arr);

        System.out.println("The next greater elements are: ");
        for (int num : ans) {
            System.out.print(num + " ");
        }
    }
}

